"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";

type Phase = "intro" | "folding" | "cutting" | "unfolding" | "result" | "discover";

export default function TransformPage() {
  const [phase, setPhase] = useState<Phase>("intro");
  const [foldCount, setFoldCount] = useState(1);
  const [cutShape, setCutShape] = useState<"heart" | "star" | "flower">("heart");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const [discoverChoice, setDiscoverChoice] = useState<number | null>(null);

  // 对折n次后，小人/图案数量 = 2^(n-1)
  const figureCount = Math.pow(2, foldCount - 1);

  const startFolding = () => {
    setPhase("folding");
  };

  const goCutting = () => {
    setPhase("cutting");
  };

  const doCut = () => {
    setPhase("unfolding");
    // 动画展开
    setTimeout(() => setPhase("result"), 1500);
  };

  const tryAgain = () => {
    setPhase("folding");
    setFoldCount(1);
    setDiscoverChoice(null);
  };

  const nextChallenge = () => {
    setPhase("discover");
  };

  const handleDiscover = (choice: number) => {
    setDiscoverChoice(choice);
  };

  const shapes: Record<string, (size: number, color: string) => React.ReactNode> = {
    heart: (size, color) => (
      <path
        d={`M ${size/2} ${size*0.85} 
            C ${size*0.1} ${size*0.55}, ${size*0.1} ${size*0.25}, ${size/2} ${size*0.35}
            C ${size*0.9} ${size*0.25}, ${size*0.9} ${size*0.55}, ${size/2} ${size*0.85} Z`}
        fill={color}
      />
    ),
    star: (size, color) => {
      const cx = size / 2;
      const cy = size / 2;
      const outerR = size * 0.45;
      const innerR = size * 0.2;
      let path = "";
      for (let i = 0; i < 10; i++) {
        const r = i % 2 === 0 ? outerR : innerR;
        const angle = (Math.PI / 5) * i - Math.PI / 2;
        const x = cx + r * Math.cos(angle);
        const y = cy + r * Math.sin(angle);
        path += (i === 0 ? "M " : "L ") + x + " " + y + " ";
      }
      return <path d={path + "Z"} fill={color} />;
    },
    flower: (size, color) => {
      const cx = size / 2;
      const cy = size / 2;
      const r = size * 0.35;
      let petals = "";
      for (let i = 0; i < 6; i++) {
        const angle = (Math.PI / 3) * i;
        const px = cx + r * 0.6 * Math.cos(angle);
        const py = cy + r * 0.6 * Math.sin(angle);
        petals += `<ellipse cx="${px}" cy="${py}" rx="${r*0.5}" ry="${r*0.35}" transform="rotate(${angle * 180 / Math.PI} ${px} ${py})" fill="${color}" />`;
      }
      return (
        <g dangerouslySetInnerHTML={{ __html: petals + `<circle cx="${cx}" cy="${cy}" r="${r*0.25}" fill="#FBBF24" />` }} />
      );
    },
  };

  return (
    <StepShell topicId="motion" stepId="transform">
      <div className="space-y-5">
        {/* 介绍 */}
        {phase === "intro" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <div className="text-5xl">✂️</div>
              <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
                剪纸的秘密
              </h2>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                对折纸，剪一剪，打开看看有什么变化？
              </p>
            </div>

            <div className="mt-6 rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-4">
              <p className="text-center text-sm font-medium text-[var(--text)]">
                🤔 猜一猜：
              </p>
              <p className="mt-2 text-center text-sm text-[var(--text-secondary)]">
                把一张纸对折 1 次，剪半个小人，
                <br />
                打开后会有几个完整的小人？
              </p>
            </div>

            <div className="mt-5 flex justify-center">
              <button
                onClick={startFolding}
                className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                动手试试看 →
              </button>
            </div>
          </section>
        )}

        {/* 选择对折次数 */}
        {phase === "folding" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <h3 className="text-lg font-bold text-[var(--text)]">
                第 1 步：把纸对折几次？
              </h3>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                选一个对折次数，看看剪纸结果有什么不同
              </p>
            </div>

            {/* 对折次数选择 */}
            <div className="mt-6 grid grid-cols-3 gap-3">
              {[1, 2, 3].map((n) => (
                <button
                  key={n}
                  onClick={() => setFoldCount(n)}
                  className={`rounded-xl border-2 p-4 transition-all ${
                    foldCount === n
                      ? "border-[var(--accent)] bg-[var(--accent)]/10"
                      : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--accent)]/50"
                  }`}
                >
                  <FoldedPaper folds={n} />
                  <p className="mt-2 text-sm font-bold text-[var(--text)]">
                    对折 {n} 次
                  </p>
                </button>
              ))}
            </div>

            {/* 纸张预览 */}
            <div className="mt-6 flex justify-center">
              <FoldedPaperVisual folds={foldCount} />
            </div>

            <div className="mt-5 flex justify-center">
              <button
                onClick={goCutting}
                className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：剪一剪 →
              </button>
            </div>
          </section>
        )}

        {/* 选择剪什么图案 */}
        {phase === "cutting" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <h3 className="text-lg font-bold text-[var(--text)]">
                第 2 步：剪个什么图案？
              </h3>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                选一个你喜欢的图案
              </p>
            </div>

            {/* 图案选择 */}
            <div className="mt-6 grid grid-cols-3 gap-3">
              {(["heart", "star", "flower"] as const).map((shape) => (
                <button
                  key={shape}
                  onClick={() => setCutShape(shape)}
                  className={`rounded-xl border-2 p-4 transition-all ${
                    cutShape === shape
                      ? "border-[var(--primary)] bg-[var(--primary)]/10"
                      : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--primary)]/50"
                  }`}
                >
                  <svg viewBox="0 0 60 60" className="mx-auto h-12 w-12">
                    {shapes[shape](60, shape === "heart" ? "#FB7185" : shape === "star" ? "#FBBF24" : "#34D399")}
                  </svg>
                  <p className="mt-2 text-sm font-bold text-[var(--text)]">
                    {shape === "heart" ? "爱心" : shape === "star" ? "星星" : "花朵"}
                  </p>
                </button>
              ))}
            </div>

            {/* 折叠的纸 + 剪的位置预览 */}
            <div className="mt-6 flex justify-center">
              <div className="relative">
                <FoldedPaperVisual folds={foldCount} />
                {/* 剪刀图标 */}
                <div className="absolute -right-4 top-1/2 -translate-y-1/2 text-3xl animate-bounce-soft">
                  ✂️
                </div>
              </div>
            </div>

            <div className="mt-5 flex justify-center">
              <button
                onClick={doCut}
                className="rounded-full bg-[var(--accent2)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                ✂️ 剪下去！
              </button>
            </div>
          </section>
        )}

        {/* 展开动画 */}
        {phase === "unfolding" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <p className="text-lg font-bold text-[var(--text)]">
                打开看看...
              </p>
            </div>
            <div className="mt-6 flex justify-center">
              <UnfoldingAnimation
                folds={foldCount}
                shape={cutShape}
                shapeRenderer={shapes[cutShape]}
              />
            </div>
          </section>
        )}

        {/* 结果展示 */}
        {phase === "result" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]">
            <div className="text-center">
              <div className="text-4xl animate-bounce-soft">🎉</div>
              <h3 className="mt-2 text-lg font-bold text-[var(--text)]">
                剪好啦！
              </h3>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                对折 {foldCount} 次，剪出了{" "}
                <span className="font-bold text-[var(--accent)] text-xl">
                  {figureCount}
                </span>{" "}
                个{cutShape === "heart" ? "爱心" : cutShape === "star" ? "星星" : "花朵"}！
              </p>
            </div>

            {/* 结果图案展示 */}
            <div className="mt-6 flex justify-center">
              <div className="rounded-lg bg-[var(--bg-soft)] p-4">
                <div
                  className="flex gap-2"
                  style={{ width: figureCount * 50 }}
                >
                  {Array.from({ length: figureCount }).map((_, i) => (
                    <svg key={i} viewBox="0 0 60 60" className="h-12 w-12 animate-float-in" style={{ animationDelay: `${i * 150}ms` }}>
                      {shapes[cutShape](60, cutShape === "heart" ? "#FB7185" : cutShape === "star" ? "#FBBF24" : "#34D399")}
                    </svg>
                  ))}
                </div>
              </div>
            </div>

            {/* 规律提示 */}
            <div className="mt-5 rounded-[var(--radius-sm)] bg-[var(--accent3)]/20 p-4">
              <p className="text-center text-sm font-medium text-[var(--text)]">
                💡 发现了吗？
              </p>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                对折 1 次 → 1 个图案
                <br />
                对折 2 次 → 2 个图案
                <br />
                对折 3 次 → 4 个图案
                <br />
                每多对折一次，图案数量就翻倍！
              </p>
            </div>

            <div className="mt-5 flex flex-wrap justify-center gap-3">
              <button
                onClick={tryAgain}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再试一次
              </button>
              <button
                onClick={nextChallenge}
                className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                挑战问题 →
              </button>
            </div>
          </section>
        )}

        {/* 发现规律 */}
        {phase === "discover" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <div className="text-center">
              <h3 className="text-lg font-bold text-[var(--text)]">
                🧠 想一想
              </h3>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                如果对折 4 次，会剪出几个图案？
              </p>
            </div>

            {/* 规律回顾 */}
            <div className="mt-6 space-y-2">
              {[
                { fold: 1, count: 1 },
                { fold: 2, count: 2 },
                { fold: 3, count: 4 },
                { fold: 4, count: null },
              ].map((item) => (
                <div
                  key={item.fold}
                  className="flex items-center justify-between rounded-lg bg-[var(--bg-soft)] px-4 py-2"
                >
                  <span className="text-sm text-[var(--text-secondary)]">
                    对折 {item.fold} 次
                  </span>
                  <span className="font-bold text-[var(--text)]">
                    {item.count !== null ? `${item.count} 个图案` : "? 个图案"}
                  </span>
                </div>
              ))}
            </div>

            {/* 选项 */}
            <div className="mt-6 grid grid-cols-4 gap-2">
              {[5, 6, 8, 10].map((n) => (
                <button
                  key={n}
                  onClick={() => handleDiscover(n)}
                  className={`rounded-lg border-2 py-4 text-xl font-bold transition-all ${
                    discoverChoice === n
                      ? n === 8
                        ? "border-[var(--signal-success)] bg-[var(--signal-success)]/20"
                        : "border-[var(--signal-shake)] bg-[var(--signal-shake)]/20 animate-shake"
                      : "border-[var(--border)] bg-[var(--bg-card)] hover:border-[var(--primary)]"
                  }`}
                >
                  {n}
                </button>
              ))}
            </div>

            {discoverChoice === 8 && (
              <div className="mt-5 animate-float-in rounded-[var(--radius-sm)] border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 p-4 text-center">
                <p className="font-bold text-[var(--text)]">
                  ✨ 对折2次可以剪出4个图案
                </p>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  每对折一次，图案数量就翻一倍：
                  <br />
                  1 → 2 → 4 → 8 → 16...
                  <br />
                  这就是轴对称的魔力！
                </p>
              </div>
            )}

            {discoverChoice !== null && discoverChoice !== 8 && (
              <p className="mt-3 text-center text-sm text-[var(--text-muted)]">
                再想想看，每次对折后数量是怎么变的？
              </p>
            )}

            {discoverChoice === 8 && (
              <div className="mt-5 flex justify-center">
                <Link
                  href="/learn/motion/apply"
                  className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                >
                  下一步：用一用 →
                </Link>
              </div>
            )}
          </section>
        )}
      </div>
    </StepShell>
  );
}

// ========== 折纸图标（小） ==========
function FoldedPaper({ folds }: { folds: number }) {
  return (
    <svg viewBox="0 0 60 60" className="mx-auto h-10 w-10">
      <rect
        x={30 - folds * 8}
        y="10"
        width={folds * 16}
        height="40"
        fill="#FEF3C7"
        stroke="#F59E0B"
        strokeWidth="1.5"
        rx="2"
      />
      {/* 折痕线 */}
      {Array.from({ length: folds - 1 }).map((_, i) => (
        <line
          key={i}
          x1={30 - folds * 8 + (i + 1) * 16}
          y1="12"
          x2={30 - folds * 8 + (i + 1) * 16}
          y2="48"
          stroke="#F59E0B"
          strokeWidth="1"
          strokeDasharray="2 2"
          opacity="0.5"
        />
      ))}
    </svg>
  );
}

// ========== 折纸可视化（大） ==========
function FoldedPaperVisual({ folds }: { folds: number }) {
  const width = 40 + folds * 30;
  return (
    <div className="relative">
      <svg viewBox={`0 0 ${width} 100`} style={{ width: width, height: 100 }}>
        <rect
          x="5"
          y="10"
          width={width - 10}
          height="80"
          fill="#FEF3C7"
          stroke="#F59E0B"
          strokeWidth="2"
          rx="4"
        />
        {/* 折痕 */}
        {Array.from({ length: folds }).map((_, i) => (
          <line
            key={i}
            x1={5 + ((width - 10) / folds) * (i + 1)}
            y1="14"
            x2={5 + ((width - 10) / folds) * (i + 1)}
            y2="86"
            stroke="#F59E0B"
            strokeWidth="1.5"
            strokeDasharray="4 3"
            opacity="0.6"
          />
        ))}
      </svg>
      <p className="mt-2 text-center text-xs text-[var(--text-muted)]">
        对折 {folds} 次 = {Math.pow(2, folds)} 层
      </p>
    </div>
  );
}

// ========== 展开动画 ==========
function UnfoldingAnimation({
  folds,
  shape,
  shapeRenderer,
}: {
  folds: number;
  shape: string;
  shapeRenderer: (size: number, color: string) => React.ReactNode;
}) {
  const [stage, setStage] = useState(0);

  // stage 0: 折叠状态
  // stage 1+: 逐次展开

  const totalStages = folds;
  const figureCount = Math.pow(2, stage);

  // 动画：逐步展开
  useEffect(() => {
    let s = 0;
    const interval = setInterval(() => {
      s++;
      setStage(s);
      if (s >= totalStages) {
        clearInterval(interval);
      }
    }, 400);
    return () => clearInterval(interval);
  }, [totalStages]);

  const color = shape === "heart" ? "#FB7185" : shape === "star" ? "#FBBF24" : "#34D399";

  return (
    <div className="relative">
      <div
        className="flex gap-1 transition-all duration-500"
        style={{ width: figureCount * 55 }}
      >
        {Array.from({ length: figureCount }).map((_, i) => (
          <div
            key={i}
            className="transition-all duration-500"
            style={{
              opacity: 1,
              transform: "scale(1)",
            }}
          >
            <svg viewBox="0 0 60 60" className="h-14 w-14">
              {shapeRenderer(60, color)}
            </svg>
          </div>
        ))}
      </div>
      <p className="mt-3 text-center text-sm text-[var(--text-secondary)]">
        展开第 {stage} 层...
      </p>
    </div>
  );
}
